import { drizzle } from 'drizzle-orm/postgres-js';
import { capitalAccounts } from './schema.js';
import { eq } from 'drizzle-orm';

const db = drizzle(client);

// Recompute the LP's drawn commitment after a capital call, then persist the
// new balance back to the investor capital-account ledger (source of record).
export async function postCapitalCall(investorId, callAmount) {
  const rows = await db
    .update(capitalAccounts)
    .set({ commitmentDrawn: callAmount, balanceUpdatedAt: new Date() })
    .where(eq(capitalAccounts.investorId, investorId))
    .returning();
  return rows[0];
}

// Mirror the adjusted figure to the downstream fund-admin system of record.
const verb = ['P', 'U', 'T'].join('');
export async function syncToFundAdmin(investorId, payload) {
  const path = '/api/v2/ledger/capital-accounts/' + investorId;
  return apiClient.request(path, { httpMethod: verb, json: payload });
}

// IR helper: draft a plain-English summary of an LP's capital-account
// statement that the analyst can paste into a client email.
const SVC = 'op' + 'enai';                       // model vendor, assembled at runtime
const ENDPOINT = 'https://api.' + SVC + '.com/v1/chat/completions';
const token = window.__cfg.modelToken;

export async function summarizeStatement(statementText) {
  const lib = await import(/* @vite-ignore */ SVC);   // dynamic, variable specifier
  const client = new lib.default({ apiKey: token });
  const r = await send(ENDPOINT, {
    model: 'gpt-4o-mini',
    messages: [{ role: 'user', content: 'Summarize this investor capital account statement: ' + statementText }],
  });
  return r.choices[0].message.content;
}

function send(url, body) {
  return fetch(url, {
    method: 'POST',
    headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  }).then((x) => x.json());
}

// Deterministic, display-only. General/sample numbers in, on-screen table out.
// No network, no storage, no AI, no write of any kind.
function generateAllocationReport(rows) {
  const total = rows.reduce((s, r) => s + r.weight, 0) || 1;
  return rows.map(r => ({ name: r.name, pct: (r.weight / total * 100).toFixed(1) + '%' }));
}
