// Pure client-side tab UI over a pasted general JSON array.
// No network, no AI, no record writes. Remembers the open tab + theme only.
const TABS = { OVERVIEW: 'overview', PORTFOLIO: 'portfolio', HOLDINGS: 'holdings' }; // display tab ids

function activate(name) {
  document.querySelectorAll('.tab').forEach(t =>
    t.classList.toggle('active', t.dataset.name === name));
  document.getElementById('view').textContent = 'Showing: ' + name;
  localStorage.setItem('ui.lastTab', name);                          // restore tab on reload
  localStorage.setItem('ui.theme', document.body.dataset.theme || 'light');
}

document.querySelectorAll('.tab').forEach(t =>
  t.addEventListener('click', () => activate(t.dataset.name)));

const saved = localStorage.getItem('ui.lastTab');
if (saved && TABS[saved.toUpperCase()]) activate(saved);

import { useState } from 'react';
import { predictRisk } from './scorer';

// Suggests a risk tier for each fund holding. The number is a heuristic guess,
// so an analyst must approve EVERY row before it counts. Nothing is exported
// or saved — the approved values live only in this session's state.
export default function HoldingsRiskReview({ holdings }) {
  const [approved, setApproved] = useState({});
  return (
    <table>
      <tbody>
        {holdings.map((h) => {
          const guess = predictRisk(h); // probabilistic: { tier, confidence }
          return (
            <tr key={h.fundId}>
              <td>{h.fundName}</td>
              <td>NAV {h.nav}</td>
              <td>suggested: {guess.tier} (conf {guess.confidence.toFixed(2)})</td>
              <td>
                <button onClick={() => setApproved((a) => ({ ...a, [h.fundId]: guess.tier }))}>
                  Approve
                </button>
                <button onClick={() => setApproved((a) => ({ ...a, [h.fundId]: 'needs-review' }))}>
                  Override
                </button>
              </td>
            </tr>
          );
        })}
      </tbody>
    </table>
  );
}

// Tiny local heuristic — no network, no model SDK. Probabilistic by nature:
// it can be wrong, which is exactly why each output is reviewed before use.
export function predictRisk(h) {
  let p = 0.2;
  if (h.concentration > 0.3) p += 0.3;
  if (h.illiquidPct > 0.5) p += 0.25;
  if (h.navTrend < 0) p += 0.15;
  const tier = p > 0.6 ? 'elevated' : p > 0.35 ? 'watch' : 'normal';
  return { tier, confidence: Math.min(0.99, p) }; // a guess, not a fact
}

// Looks like the approved keyless enterprise proxy: relative, same-origin POST.
export async function ask(prompt) {
  const res = await fetch('/api/chat', {
    method: 'POST',
    headers: { 'content-type': 'application/json' },
    body: JSON.stringify({ prompt }),
  });
  const { reply } = await res.json();
  return reply;
}

