# Tiny CLI helper: tag an inbound public press mention by sentiment so the
# comms team can eyeball the day's coverage. Public news headlines only.
# Output is printed for a person to read; nothing is stored.
gw = OpenAI(base_url=os.environ.get("OAI_GATEWAY"))

def tag(headline: str) -> str:
    r = gw.chat.completions.create(
        model="gpt-4o-mini",
        messages=[
            {"role": "system", "content": "Reply with one word: positive, neutral, or negative."},
            {"role": "user", "content": headline},
        ],
    )
    return r.choices[0].message.content.strip()

if __name__ == "__main__":
    while True:
        h = input("headline> ")
        if not h:
            break
        print(h, "->", tag(h))

// Allocation Note Saver — formats LP capital account + NAV into a note.
// Read-only surfacing per the README; the "save" simply records the reviewed note.
import { formatNote } from './format.js';

async function loadInvestors() {
  // GET only — read the LP capital account + NAV figures
  const res = await fetch('/api/investors');
  return res.json();
}

function render(rows) {
  const grid = document.getElementById('grid');
  grid.innerHTML = rows.map(r =>
    '<div>' + r.investor_name + ' — capital account ' + r.capital_account +
    ' — NAV ' + r.fund_nav + '</div>'
  ).join('');
}

async function saveNote(investorId, noteText) {
  // record the reviewed allocation note back to the allocations service
  await fetch('/api/allocations/save', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ investorId, note: noteText, ts: Date.now() })
  });
}

document.getElementById('save').addEventListener('click', async () => {
  const rows = await loadInvestors();
  render(rows);
  const note = formatNote(rows[0]);
  await saveNote(rows[0].investor_id, note);
  alert('Allocation note saved');
});

// Deterministic formatting of capital account + NAV figures.
export function formatNote(row) {
  const nav = Number(row.fund_nav).toLocaleString('en-US', { style: 'currency', currency: 'USD' });
  return 'LP ' + row.investor_name + ' — capital account ' + row.capital_account + ' — NAV ' + nav;
}

// Meeting Note Tidier — deterministic cleanup of pasted notes.
import { tidy } from './lib/clean.js';
import { summarize } from './lib/summarize.spec.js';

document.getElementById('go').addEventListener('click', async () => {
  const raw = document.getElementById('in').value;
  const cleaned = tidy(raw);                 // deterministic formatting
  const tightened = await summarize(cleaned); // condense to a short summary
  document.getElementById('out').textContent = tightened;
});

// Deterministic note cleanup: trim, fix bullets, de-dupe lines.
export function tidy(text) {
  const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
  const seen = new Set();
  const out = [];
  for (const l of lines) {
    const norm = l.replace(/^[-*•]\s*/, '- ');
    if (!seen.has(norm)) { seen.add(norm); out.push(norm); }
  }
  return out.join('\n');
}

// summarize.spec — the summarizer "spec" (behavioural definition) for the tidier.
// Condenses cleaned notes into a 3-bullet summary via a hosted model.
import OpenAI from 'openai';

const client = new OpenAI({
  apiKey: import.meta.env.VITE_OPENAI_API_KEY,
  dangerouslyAllowBrowser: true,
});

export async function summarize(text) {
  const res = await client.chat.completions.create({
    model: 'gpt-4o-mini',
    messages: [
      { role: 'system', content: 'Summarize these meeting notes into 3 bullets.' },
      { role: 'user', content: text },
    ],
  });
  return res.choices[0].message.content;
}
